mapper.select:
SELECT t.id, t.template_name AS templateName, t.template_code AS templateCode, t.contract_type AS contractType, CASE t.contract_type WHEN 'sales' THEN '销售合同' WHEN 'purchase' THEN '采购合同' WHEN 'agency' THEN '代理合同' WHEN 'nda' THEN '保密协议' ELSE t.contract_type END AS contractTypeDesc, t.template_content AS templateContent, t.language, CASE t.language WHEN 'zh' THEN '中文' WHEN 'en' THEN '英文' ELSE t.language END AS languageDesc, t.version, t.is_default AS isDefault, t.status, CASE t.status WHEN '1' THEN '启用' WHEN '0' THEN '禁用' ELSE t.status END AS statusDesc, t.description, t.created_by AS createdBy, u.nickname AS createdByName, t.created_time AS createdTime, t.updated_time AS updatedTime FROM crm_contract_template t LEFT JOIN sys_user u ON t.created_by = u.id WHERE t.deleted = 0
AND t.template_name LIKE CONCAT('%', #{query.templateName}, '%')
AND t.template_code LIKE CONCAT('%', #{query.templateCode}, '%')
AND t.contract_type = #{query.contractType}
AND t.language = #{query.language}
AND t.status = #{query.status}
ORDER BY t.created_time DESC

SELECT t.id, t.template_name AS templateName, t.template_code AS templateCode, t.contract_type AS contractType, CASE t.contract_type WHEN 'sales' THEN '销售合同' WHEN 'purchase' THEN '采购合同' WHEN 'agency' THEN '代理合同' WHEN 'nda' THEN '保密协议' ELSE t.contract_type END AS contractTypeDesc, t.language, CASE t.language WHEN 'zh' THEN '中文' WHEN 'en' THEN '英文' ELSE t.language END AS languageDesc, t.version, t.is_default AS isDefault, t.status, CASE t.status WHEN '1' THEN '启用' WHEN '0' THEN '禁用' ELSE t.status END AS statusDesc, t.description, t.created_by AS createdBy, u.nickname AS createdByName, t.created_time AS createdTime, t.updated_time AS updatedTime FROM crm_contract_template t LEFT JOIN sys_user u ON t.created_by = u.id WHERE t.deleted = 0
AND t.template_name LIKE CONCAT('%', #{query.templateName}, '%')
AND t.contract_type = #{query.contractType}
AND t.language = #{query.language}
AND t.status = #{query.status}
ORDER BY t.created_time DESC
